ALGORITHM DES_Encrypt
INPUT: 64-bit Plaintext P, 64-bit Key K
OUTPUT: 64-bit Ciphertext C

BEGIN
    // Step 1: Generate 16 round keys from the original key
    RoundKeys = GenerateRoundKeys(K)

    // Step 2: Apply Initial Permutation (IP)
    P = IP(P)

    // Step 3: Divide into left and right halves
    L[0] = P[0..31]    // First 32 bits
    R[0] = P[32..63]   // Last 32 bits

    // Step 4: Perform 16 rounds of Feistel structure
    FOR i FROM 1 TO 16 DO
        // Expansion Permutation: Expand R[i-1] from 32 to 48 bits
        ExpandedR = ExpansionPermutation(R[i-1])

        // XOR with round key
        Xored = ExpandedR XOR RoundKeys[i]

        // S-Box Substitution: 8 S-boxes, each takes 6 bits -> 4 bits
        Substituted = S_Box_Substitution(Xored)

        // Permutation (P-box)
        Permuted = Permutation(Substituted)

        // Compute new L and R
        L[i] = R[i-1]
        R[i] = L[i-1] XOR Permuted
    END FOR

    // Step 5: Swap left and right halves
    Temp = R[16]
    R[16] = L[16]
    L[16] = Temp

    // Step 6: Apply Final Permutation (FP)
    C = FP(L[16] || R[16])

    RETURN C
END

// Helper: Generate 16 round keys from 56-bit key
ALGORITHM GenerateRoundKeys
INPUT: 64-bit Key K (56 bits used, 8 parity bits)
OUTPUT: Array of 16 48-bit round keys

BEGIN
    // Remove parity bits and perform initial key permutation
    K = PC1(K)  // Permuted Choice 1

    // Split into C (left) and D (right) halves
    C[0] = K[0..27]
    D[0] = K[28..55]

    // Generate 16 round keys
    FOR i FROM 1 TO 16 DO
        // Left shift C and D
        C[i] = LeftShift(C[i-1], ShiftSchedule[i])
        D[i] = LeftShift(D[i-1], ShiftSchedule[i])

        // Combine and apply Permuted Choice 2
        RoundKeys[i] = PC2(C[i] || D[i])
    END FOR

    RETURN RoundKeys
END

/*
 * DES (Data Encryption Standard) Implementation in C
 * Educational example demonstrating the DES encryption algorithm
 */

#include <stdio.h>
#include <stdint.h>
#include <string.h>

/* Initial Permutation (IP) Table */
const int IP[] = {
    58, 50, 42, 34, 26, 18, 10, 2,
    60, 52, 44, 36, 28, 20, 12, 4,
    62, 54, 46, 38, 30, 22, 14, 6,
    64, 56, 48, 40, 32, 24, 16, 8,
    57, 49, 41, 33, 25, 17, 9, 1,
    59, 51, 43, 35, 27, 19, 11, 3,
    61, 53, 45, 37, 29, 21, 13, 5,
    63, 55, 47, 39, 31, 23, 15, 7
};

/* Final Permutation (FP) Table */
const int FP[] = {
    40, 8, 48, 16, 56, 24, 64, 32,
    39, 7, 47, 15, 55, 23, 63, 31,
    38, 6, 46, 14, 54, 22, 62, 30,
    37, 5, 45, 13, 53, 21, 61, 29,
    36, 4, 44, 12, 52, 20, 60, 28,
    35, 3, 43, 11, 51, 19, 59, 27,
    34, 2, 42, 10, 50, 18, 58, 26,
    33, 1, 41, 9, 49, 17, 57, 25
};

/* Expansion Permutation (E) Table - 32 to 48 bits */
const int E[] = {
    32, 1, 2, 3, 4, 5,
    4, 5, 6, 7, 8, 9,
    8, 9, 10, 11, 12, 13,
    12, 13, 14, 15, 16, 17,
    16, 17, 18, 19, 20, 21,
    20, 21, 22, 23, 24, 25,
    24, 25, 26, 27, 28, 29,
    28, 29, 30, 31, 32, 1
};

/* Permutation (P) Table */
const int P[] = {
    16, 7, 20, 21, 29, 12, 28, 17,
    1, 15, 23, 26, 5, 18, 31, 10,
    2, 8, 24, 14, 32, 27, 3, 9,
    19, 13, 30, 6, 22, 11, 4, 25
};

/* PC-1: Permuted Choice 1 */
const int PC1[] = {
    57, 49, 41, 33, 25, 17, 9, 1,
    58, 50, 42, 34, 26, 18, 10, 2,
    59, 51, 43, 35, 27, 19, 11, 3,
    60, 52, 44, 36, 63, 55, 47, 39,
    31, 23, 15, 7, 62, 54, 46, 38,
    30, 22, 14, 6, 61, 53, 45, 37,
    29, 21, 13, 5, 28, 20, 12, 4
};

/* PC-2: Permuted Choice 2 */
const int PC2[] = {
    14, 17, 11, 24, 1, 5, 3, 28,
    15, 6, 21, 10, 23, 19, 12, 4,
    26, 8, 16, 7, 27, 20, 13, 2,
    41, 52, 31, 37, 47, 55, 30, 40,
    51, 45, 33, 48, 44, 49, 39, 56,
    34, 53, 46, 42, 50, 36, 29, 32
};

/* Shift schedule for key generation */
const int SHIFT_SCHEDULE[] = {1, 1, 2, 2, 2, 2, 2, 2, 1, 2, 2, 2, 2, 2, 2, 1};

/* Convert hex string to 64-bit value */
uint64_t hex_to_uint64(const char *hex) {
    return strtoull(hex, NULL, 16);
}

/* Convert 64-bit value to binary string */
void uint64_to_binary(uint64_t value, char *binary) {
    for (int i = 0; i < 64; i++) {
        binary[i] = ((value >> (63 - i)) & 1) ? '1' : '0';
    }
    binary[64] = '\0';
}

/* Apply permutation to block */
void permute(const char *input, char *output, const int *table, int size) {
    for (int i = 0; i < size; i++) {
        output[i] = input[table[i] - 1];
    }
    output[size] = '\0';
}

/* XOR two binary strings */
void xor_binary(const char *a, const char *b, char *result, int size) {
    for (int i = 0; i < size; i++) {
        result[i] = (a[i] == b[i]) ? '0' : '1';
    }
    result[size] = '\0';
}

/* Left circular shift */
void left_shift(const char *input, char *output, int shift, int size) {
    shift = shift % size;
    strncpy(output, input + shift, size - shift);
    strncpy(output + size - shift, input, shift);
    output[size] = '\0';
}

/* Generate 16 round keys from main key */
void generate_round_keys(uint64_t key, char round_keys[16][49]) {
    char key_binary[65];
    char permuted_key[57];
    char C[29], D[29];
    char temp[57];

    uint64_to_binary(key, key_binary);

    /* Apply PC-1 */
    permute(key_binary, permuted_key, PC1, 56);

    /* Split into C and D */
    strncpy(C, permuted_key, 28);
    C[28] = '\0';
    strncpy(D, permuted_key + 28, 28);
    D[28] = '\0';

    /* Generate 16 round keys */
    for (int i = 0; i < 16; i++) {
        /* Left shift */
        left_shift(C, C, SHIFT_SCHEDULE[i], 28);
        left_shift(D, D, SHIFT_SCHEDULE[i], 28);

        /* Combine and apply PC-2 */
        strcpy(temp, C);
        strcat(temp, D);
        permute(temp, round_keys[i], PC2, 48);
    }
}

/* S-Box substitution (simplified) */
void s_box_substitution(const char *input, char *output) {
    /* Simplified S-box for demonstration */
    for (int i = 0; i < 8; i++) {
        int row, col, value;
        char block[7];

        strncpy(block, input + (i * 6), 6);
        block[6] = '\0';

        /* Extract row and column */
        row = (block[0] - '0') * 2 + (block[5] - '0');
        col = (block[1] - '0') * 8 + (block[2] - '0') * 4 + 
              (block[3] - '0') * 2 + (block[4] - '0');

        /* Simple substitution */
        value = (row * 16 + col) % 16;

        /* Convert to 4-bit binary */
        output[i * 4] = ((value >> 3) & 1) + '0';
        output[i * 4 + 1] = ((value >> 2) & 1) + '0';
        output[i * 4 + 2] = ((value >> 1) & 1) + '0';
        output[i * 4 + 3] = (value & 1) + '0';
    }
    output[32] = '\0';
}

/* Main DES encryption function */
uint64_t des_encrypt(uint64_t plaintext, uint64_t key) {
    char pt_binary[65], permuted[65];
    char L[33], R[33], L_next[33], R_next[33];
    char expanded[49], xored[49], substituted[33], permuted_p[33];
    char round_keys[16][49];

    /* Generate round keys */
    generate_round_keys(key, round_keys);

    /* Convert plaintext to binary */
    uint64_to_binary(plaintext, pt_binary);

    /* Initial Permutation */
    permute(pt_binary, permuted, IP, 64);

    /* Split into L and R */
    strncpy(L, permuted, 32);
    L[32] = '\0';
    strncpy(R, permuted + 32, 32);
    R[32] = '\0';

    printf("Initial: L0 = %.8llX, R0 = %.8llX\n", 
           (unsigned long long)strtoull(L, NULL, 2),
           (unsigned long long)strtoull(R, NULL, 2));

    /* 16 rounds of DES */
    for (int i = 0; i < 16; i++) {
        /* Save current R */
        strcpy(L_next, R);

        /* Expansion Permutation */
        permute(R, expanded, E, 48);

        /* XOR with round key */
        xor_binary(expanded, round_keys[i], xored, 48);

        /* S-Box Substitution */
        s_box_substitution(xored, substituted);

        /* Permutation (P) */
        permute(substituted, permuted_p, P, 32);

        /* XOR with L */
        xor_binary(L, permuted_p, R_next, 32);

        /* Update L and R */
        strcpy(L, L_next);
        strcpy(R, R_next);

        if (i < 3) {
            printf("Round %d: L = %.8llX, R = %.8llX\n", i + 1,
                   (unsigned long long)strtoull(L, NULL, 2),
                   (unsigned long long)strtoull(R, NULL, 2));
        }
    }

    /* Swap L and R */
    strcpy(permuted, R);
    strcat(permuted, L);

    /* Final Permutation */
    permute(permuted, permuted, FP, 64);

    return strtoull(permuted, NULL, 2);
}

/* Convert binary string to hex string */
void binary_to_hex_string(const char *binary, char *hex) {
    for (int i = 0; i < 16; i++) {
        int value = 0;
        for (int j = 0; j < 4; j++) {
            value = value * 2 + (binary[i * 4 + j] - '0');
        }
        sprintf(hex + i, "%X", value);
    }
    hex[16] = '\0';
}

int main() {
    /* Example from the topic */
    const char *plaintext_hex = "1234567890ABCDEF";
    const char *key_hex = "1122334455667788";

    uint64_t plaintext = hex_to_uint64(plaintext_hex);
    uint64_t key = hex_to_uint64(key_hex);

    printf("==================================================\n");
    printf("DES Encryption Example\n");
    printf("==================================================\n");
    printf("Plaintext: 0x%s\n", plaintext_hex);
    printf("Key:       0x%s\n", key_hex);
    printf("--------------------------------------------------\n");

    uint64_t ciphertext = des_encrypt(plaintext, key);

    printf("--------------------------------------------------\n");
    printf("Ciphertext: 0x%016llX\n", (unsigned long long)ciphertext);
    printf("==================================================\n");

    return 0;
}
